/**
 * Admin Calendar functionality for Vacation Rental management
 * Uses Flatpickr for beautiful, minimal calendar interface
 */

class VacationRentalCalendar {
    constructor(options = {}) {
        this.options = {
            propertyId: null,
            container: '#vacation-rental-calendar',
            apiEndpoint: '/admin/vacation-rentals/availability-data',
            blockDatesEndpoint: '/admin/vacation-rentals/block-dates',
            unblockDatesEndpoint: '/admin/vacation-rentals/unblock-dates',
            ...options
        };
        
        this.calendar = null;
        this.availabilityData = {};
        this.selectedDates = [];
        this.init();
    }

    init() {
        this.loadAvailabilityData();
        this.initializeCalendar();
        this.bindEvents();
    }

    async loadAvailabilityData() {
        if (!this.options.propertyId) return;

        try {
            const response = await fetch(`${this.options.apiEndpoint}?property_id=${this.options.propertyId}`);
            const data = await response.json();
            this.availabilityData = data.data || {};
        } catch (error) {
            console.error('Failed to load availability data:', error);
        }
    }

    initializeCalendar() {
        const container = document.querySelector(this.options.container);
        if (!container) return;

        // Create calendar HTML structure
        container.innerHTML = `
            <div class="calendar-header">
                <div class="calendar-controls">
                    <button type="button" class="btn btn-sm btn-success" id="mark-available">
                        <i class="fas fa-check"></i> Mark Available
                    </button>
                    <button type="button" class="btn btn-sm btn-warning" id="mark-blocked">
                        <i class="fas fa-ban"></i> Block Dates
                    </button>
                    <button type="button" class="btn btn-sm btn-danger" id="mark-maintenance">
                        <i class="fas fa-tools"></i> Maintenance
                    </button>
                </div>
                <div class="calendar-legend">
                    <span class="legend-item available"><span class="color-box"></span> Available</span>
                    <span class="legend-item booked"><span class="color-box"></span> Booked</span>
                    <span class="legend-item blocked"><span class="color-box"></span> Blocked</span>
                    <span class="legend-item maintenance"><span class="color-box"></span> Maintenance</span>
                </div>
            </div>
            <div class="calendar-container">
                <input type="text" id="calendar-picker" style="display: none;">
            </div>
            <div class="selected-dates-info" id="selected-dates-info" style="display: none;">
                <h6>Selected Dates:</h6>
                <div id="selected-dates-list"></div>
                <div class="mt-2">
                    <input type="text" class="form-control" id="block-reason" placeholder="Reason for blocking (optional)">
                    <div class="mt-2">
                        <button type="button" class="btn btn-primary btn-sm" id="apply-changes">Apply Changes</button>
                        <button type="button" class="btn btn-secondary btn-sm" id="clear-selection">Clear Selection</button>
                    </div>
                </div>
            </div>
        `;

        // Initialize Flatpickr
        this.calendar = flatpickr('#calendar-picker', {
            mode: 'multiple',
            inline: true,
            dateFormat: 'Y-m-d',
            minDate: 'today',
            showMonths: 2,
            onDayCreate: (dObj, dStr, fp, dayElem) => {
                const date = dayElem.dateObj.toISOString().split('T')[0];
                const availability = this.availabilityData[date];
                
                if (availability) {
                    dayElem.classList.add(`calendar-${availability.status}`);
                    
                    if (availability.booking_number) {
                        dayElem.title = `Booked: ${availability.booking_number}`;
                    } else if (availability.reason) {
                        dayElem.title = availability.reason;
                    }
                }
            },
            onChange: (selectedDates) => {
                this.selectedDates = selectedDates.map(date => date.toISOString().split('T')[0]);
                this.updateSelectedDatesInfo();
            }
        });
    }

    updateSelectedDatesInfo() {
        const infoContainer = document.getElementById('selected-dates-info');
        const datesList = document.getElementById('selected-dates-list');
        
        if (this.selectedDates.length > 0) {
            infoContainer.style.display = 'block';
            datesList.innerHTML = this.selectedDates.map(date => 
                `<span class="badge badge-primary me-1">${date}</span>`
            ).join('');
        } else {
            infoContainer.style.display = 'none';
        }
    }

    bindEvents() {
        // Mark Available
        document.getElementById('mark-available')?.addEventListener('click', () => {
            this.currentAction = 'available';
            this.highlightActionButton('mark-available');
        });

        // Mark Blocked
        document.getElementById('mark-blocked')?.addEventListener('click', () => {
            this.currentAction = 'blocked';
            this.highlightActionButton('mark-blocked');
        });

        // Mark Maintenance
        document.getElementById('mark-maintenance')?.addEventListener('click', () => {
            this.currentAction = 'maintenance';
            this.highlightActionButton('mark-maintenance');
        });

        // Apply Changes
        document.getElementById('apply-changes')?.addEventListener('click', () => {
            this.applyChanges();
        });

        // Clear Selection
        document.getElementById('clear-selection')?.addEventListener('click', () => {
            this.clearSelection();
        });
    }

    highlightActionButton(activeId) {
        // Remove active class from all buttons
        document.querySelectorAll('.calendar-controls .btn').forEach(btn => {
            btn.classList.remove('active');
        });
        
        // Add active class to selected button
        document.getElementById(activeId)?.classList.add('active');
    }

    async applyChanges() {
        if (!this.selectedDates.length || !this.currentAction) {
            alert('Please select dates and an action');
            return;
        }

        const reason = document.getElementById('block-reason')?.value || '';
        
        try {
            const response = await fetch(this.options.blockDatesEndpoint, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'X-CSRF-TOKEN': document.querySelector('meta[name="csrf-token"]').getAttribute('content')
                },
                body: JSON.stringify({
                    property_id: this.options.propertyId,
                    dates: this.selectedDates,
                    status: this.currentAction,
                    reason: reason
                })
            });

            const result = await response.json();
            
            if (result.error) {
                alert(result.message || 'Failed to update dates');
            } else {
                // Reload availability data and refresh calendar
                await this.loadAvailabilityData();
                this.refreshCalendar();
                this.clearSelection();
                
                // Show success message
                this.showNotification('Dates updated successfully', 'success');
            }
        } catch (error) {
            console.error('Failed to apply changes:', error);
            alert('Failed to update dates');
        }
    }

    clearSelection() {
        this.selectedDates = [];
        this.calendar.clear();
        this.updateSelectedDatesInfo();
        
        // Clear active button
        document.querySelectorAll('.calendar-controls .btn').forEach(btn => {
            btn.classList.remove('active');
        });
        this.currentAction = null;
        
        // Clear reason input
        document.getElementById('block-reason').value = '';
    }

    refreshCalendar() {
        this.calendar.redraw();
    }

    showNotification(message, type = 'info') {
        // Create a simple notification
        const notification = document.createElement('div');
        notification.className = `alert alert-${type} alert-dismissible fade show position-fixed`;
        notification.style.cssText = 'top: 20px; right: 20px; z-index: 9999; min-width: 300px;';
        notification.innerHTML = `
            ${message}
            <button type="button" class="btn-close" data-bs-dismiss="alert"></button>
        `;
        
        document.body.appendChild(notification);
        
        // Auto remove after 3 seconds
        setTimeout(() => {
            notification.remove();
        }, 3000);
    }
}

// Initialize when DOM is ready
document.addEventListener('DOMContentLoaded', function() {
    // Auto-initialize if container exists
    const calendarContainer = document.querySelector('#vacation-rental-calendar');
    if (calendarContainer) {
        const propertyId = calendarContainer.dataset.propertyId;
        if (propertyId) {
            window.vacationRentalCalendar = new VacationRentalCalendar({
                propertyId: propertyId
            });
        }
    }
});
